/* Top to bottom (default direction) */
.gradient-basic {
  background-image: linear-gradient(#3498db, #2c3e50);
}

/* Left to right */
.gradient-horizontal {
  background-image: linear-gradient(to right, #e74c3c, #f39c12);
}

/* Diagonal */
.gradient-diagonal {
  background-image: linear-gradient(45deg, #8e44ad, #3498db, #2ecc71);
}

/* Custom color stop positions */
.gradient-stops {
  background-image: linear-gradient(
    to right,
    #e74c3c 0%,
    #e74c3c 30%,    /* solid red for first 30% */
    #f39c12 30%,    /* hard transition to orange */
    #f39c12 100%
  );
}

/* Transparent to color (overlay effect) */
.gradient-overlay {
  background-image: linear-gradient(
    to bottom,
    transparent,
    hsl(0 0% 0% / 0.8)
  );
}

/* Basic circular radial gradient */
.gradient-radial {
  background-image: radial-gradient(circle, #3498db, #2c3e50);
}

/* Elliptical (default shape) */
.gradient-ellipse {
  background-image: radial-gradient(ellipse, #e74c3c, #2c3e50);
}

/* Custom position */
.gradient-positioned {
  background-image: radial-gradient(
    circle at 25% 25%,
    #f39c12,
    #e74c3c,
    #8e44ad
  );
}

/* Spotlight / glow effect */
.spotlight {
  background-color: #1a1a2e;
  background-image: radial-gradient(
    circle at 50% 30%,
    hsl(220 80% 60% / 0.3),
    transparent 60%
  );
}

/* Sized gradient */
.gradient-sized {
  background-image: radial-gradient(
    circle 100px at center,
    #3498db,
    transparent
  );
}

/* Basic conic gradient (color wheel) */
.color-wheel {
  width: 200px;
  height: 200px;
  border-radius: 50%;
  background-image: conic-gradient(
    red, yellow, lime, aqua, blue, magenta, red
  );
}

/* Pie chart with hard stops */
.pie-chart {
  width: 200px;
  height: 200px;
  border-radius: 50%;
  background-image: conic-gradient(
    #3498db 0% 40%,    /* 40% blue */
    #e74c3c 40% 70%,   /* 30% red */
    #2ecc71 70% 100%    /* 30% green */
  );
}

/* Progress ring */
.progress-ring {
  width: 100px;
  height: 100px;
  border-radius: 50%;
  background-image: conic-gradient(
    from 0deg,
    #3498db 0% 75%,      /* 75% complete */
    #e0e0e0 75% 100%     /* remaining */
  );
}

/* Diagonal stripes */
.stripes {
  background-image: repeating-linear-gradient(
    45deg,
    #3498db,
    #3498db 10px,
    #2980b9 10px,
    #2980b9 20px
  );
}

/* Horizontal lines (notebook paper) */
.lined-paper {
  background-color: white;
  background-image: repeating-linear-gradient(
    to bottom,
    transparent,
    transparent 31px,
    #e0e0e0 31px,
    #e0e0e0 32px
  );
}

/* Concentric circles */
.target {
  background-image: repeating-radial-gradient(
    circle,
    #e74c3c,
    #e74c3c 10px,
    white 10px,
    white 20px
  );
}

/* Multiple gradients layered */
.grid-pattern {
  background-color: white;
  background-image:
    linear-gradient(to right, #e0e0e0 1px, transparent 1px),
    linear-gradient(to bottom, #e0e0e0 1px, transparent 1px);
  background-size: 20px 20px;
}

